def process_graph(graph_data):
    # create a copy of the graph to avoid modifying the original
    graph_copy = graph_data.copy()

    # locate the EK_AGG_BLOCK node with the specific name
    agg_node_id = None
    for n_id, attrs in graph_copy.nodes(data=True):
        if attrs.get('name') == 'ju1.a4.m4' and 'EK_AGG_BLOCK' in attrs.get('type', []):
            agg_node_id = n_id
            break

    # if the target node is not found, return empty result
    if agg_node_id is None:
        return_object = {
            'type': 'list',
            'data': [],
            'updated_graph': nx.readwrite.json_graph.node_link_data(graph_copy)
        }
        return return_object

    # collect direct child nodes (edges with RK_CONTAINS)
    child_nodes = []
    for _, child_id, e_attrs in graph_copy.out_edges(agg_node_id, data=True):
        edge_type = e_attrs.get('type', [])
        if isinstance(edge_type, list):
            if 'RK_CONTAINS' in edge_type:
                child_nodes.append(child_id)
        else:
            if edge_type == 'RK_CONTAINS':
                child_nodes.append(child_id)

    # function to sum physical_capacity_bps of all PORT descendants of a node
    def total_capacity(node_id):
        total = 0
        # traverse descendants (including the node itself)
        for desc_id in nx.descendants(graph_copy, node_id):
            desc_attrs = graph_copy.nodes[desc_id]
            if 'EK_PORT' in desc_attrs.get('type', []):
                total += desc_attrs.get('physical_capacity_bps', 0)
        # also check if the node itself is a PORT (unlikely for child of AGG_BLOCK)
        node_attrs = graph_copy.nodes[node_id]
        if 'EK_PORT' in node_attrs.get('type', []):
            total += node_attrs.get('physical_capacity_bps', 0)
        return total

    # build list of (child_name, total_capacity) tuples
    result_list = []
    for child_id in child_nodes:
        child_attrs = graph_copy.nodes[child_id]
        child_name = child_attrs.get('name')
        cap = total_capacity(child_id)
        result_list.append((child_name, cap))

    # sort the list by capacity in descending order
    result_list.sort(key=lambda x: x[1], reverse=True)

    # prepare the return object
    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)
    return_object = {
        'type': 'list',
        'data': result_list,
        'updated_graph': graph_json
    }
    return return_object

